INSERT INTO channel_configs (channel, tone, max_length, greeting_template, signature_template) VALUES
('gmail', 'formal', 500, 'Dear {customer_name},', E'Best regards,\nStreamLine Support Team\nsupport@streamline-saas.com'),
('whatsapp', 'conversational', 300, 'Hi {customer_name}! 👋', NULL),
